actionConfiguration.body:
async function () {
  const first = inpFirstName.text.trim();
  const last = inpLastName.text.trim();
  if (!first || !last) {
    showAlert("First and last name are required.", "warning");
    return;
  }
  const wantsAgreement = inpCreateRelease.isChecked;
  const uploadPaper = typeof inpUploadRelease !== "undefined" ? inpUploadRelease.isChecked : false;
  if (wantsAgreement) {
    const facilitatorId = typeof inpFacilitator !== "undefined" ? (inpFacilitator.selectedOptionValue || "").trim() : "";
    if (!facilitatorId) {
      showAlert("Please select a facilitator before creating an agreement.", "warning");
      return;
    }
  }
  if (uploadPaper) {
    const files = FilePicker1?.files || [];
    if (!files.length) {
      showAlert("Please choose at least one file to upload for the paper agreement.", "warning");
      return;
    }
  }
  const dup = await qCheckMemberDuplicate.run();
  if (dup && dup.length > 0) {
    const hit = dup[0];
    showAlert(`Member already exists (ID ${hit.member_id}). Please open the existing member instead of creating a new one.`, "error");
    storeValue("memberDupes", dup);
    return;
  }
  const inserted = await qCreateMember.run();
  const memberId = inserted?.[0]?.member_id;
  if (!memberId) throw new Error("Member insert did not return member_id.");
  await storeValue("new_member_id", memberId);
  let agRes = null;
  if (wantsAgreement) {
    const facilitatorId = typeof inpFacilitator !== "undefined" ? inpFacilitator.selectedOptionValue : null;
    const signatureMethod = uploadPaper ? "paper" : "opensign";
    const agreementStatus = uploadPaper ? "pending_review" : "pending_signature";
    await storeValue("selected_facilitator_id", facilitatorId);
    await storeValue("signature_method", signatureMethod);
    await storeValue("agreement_status", agreementStatus);
    let evidenceArr = [];
    if (uploadPaper) {
      const files = FilePicker1.files || [];
      for (const file of files) {
        const up = await apiUploadEvidence.run({
          file
        });
        const attachment = up?.data ?? up;
        if (!attachment) {
          throw new Error("Upload did not return attachment metadata.");
        }
        evidenceArr.push(attachment);
      }
    }
    await storeValue("evidence_json", JSON.stringify(evidenceArr));
    agRes = await qCreatePendingAgreement.run();
  }
  showAlert(`Member created (ID ${memberId}).`, "success");
  resetWidget("MemberForm", true);
  return {
    memberId,
    agRes
  };
}

