async function () {
  const memberId = memberProfile._requireMemberId();
  const facilitatorId = memberProfile._requireFacilitator();
  if (!facilitatorId) return;
  const files = FilePicker1?.files || [];
  if (!files.length) {
    showAlert("Please choose at least one file to upload for the paper agreement.", "warning");
    return;
  }
  const attachments = [];
  for (const f of files) {
    const uploadRes = await apiUploadEvidence.run({
      file: [f]
    });
    const normalized = memberProfile._normalizeUploadResponse(uploadRes, f);
    attachments.push(...normalized);
  }
  const evidenceJson = JSON.stringify(attachments);
  const ins = await qCreatePendingAgreement.run({
    member_id: memberId,
    facilitator_id: facilitatorId,
    signature_method: "paper",
    status: "pending_review",
    evidence_json: evidenceJson
  });
  showAlert("Paper agreement uploaded and queued for review.", "success");
  await qMemberAgreements.run();
  resetWidget("FilePicker1", true);
  return {
    attachments,
    ins
  };
}

