    }

    await Promise.allSettled([
      qMemberById.run(),
      qMemberAgreements.run(),
      qMemberReleases.run(),
      // If you want facilitator dropdown populated on load:
      qListFacilitators?.run?.(),
    ]);
  },

  _requireMemberId() {
    const memberId = appsmith.URL.queryParams.member_id;
    if (!memberId) throw new Error("Missing member_id in URL.");
    return memberId;
