    const facilitatorId = inpFacilitator?.selectedOptionValue;
    if (!facilitatorId) {
      showAlert("Please select a facilitator before creating an agreement.", "warning");
      return null;
    }
    return facilitatorId;
  },

  _normalizeUploadResponse(uploadRes, fallbackFile) {
    // NocoDB commonly returns an array of attachment objects.
    // But responses can vary depending on proxy/plugin; handle a few shapes.
    const r = uploadRes?.data ?? uploadRes;

    if (Array.isArray(r)) return r;
    if (Array.isArray(r?.files)) return r.files;
    if (r && typeof r === "object") return [r];

    // Worst case: construct minimal attachment object so evidence isn't empty
    return [{
      title: fallbackFile?.name || "upload",
      mimetype: fallbackFile?.type,
      size: fallbackFile?.size,
    }];
  },

  async sendOpensignRelease() {
    const memberId = this._requireMemberId();
    const facilitatorId = this._requireFacilitator();
    if (!facilitatorId) return;

    // Create the pending agreement record first (pending_signature)
    const ins = await qCreatePendingAgreement.run({
      member_id: memberId,
      facilitator_id: facilitatorId,
      signature_method: "opensign",
      status: "pending_signature",
      evidence_json: "[]",
